<?php/*********************************************** This file displays the change non-sensitive ** user data form.  It submits to itself, and  ** displays a message each time you submit.    ************************************************/// A file with the database host, user, password, and selected databaserequire_once('../assets/dbconnect.php');include_once('db_header_footer.php');include_once('../assets/db_inc_login_funcs.php');if (!user_isloggedin()) {  echo '<P>You are not logged in, or this is not your user profile.</P>';} else {  $user_name = $_COOKIE['user_name'];  if ($_POST['submit'] == "Edit user data" && strlen($_POST['gender']) == 1 && strlen($_POST['priv_profile']) == 1) {    // Send data to db    // I'm not bothering to check the stringlength of these    // because I'm URL-encoding them    $as_photo_url = addslashes($_POST['photo_url']);    $ue_photo_url = urlencode($as_photo_url);    $as_homepage_url = addslashes($_POST['homepage_url']);    $ue_homepage_url = urlencode($as_homepage_url);    $as_fav_link1 = addslashes($_POST['fav_link1']);    $ue_fav_link1 = urlencode($as_fav_link1);    $as_fav_link2 = addslashes($_POST['fav_link2']);    $ue_fav_link2 = urlencode($as_fav_link2);    $as_fav_link3 = addslashes($_POST['fav_link3']);    $ue_fav_link3 = urlencode($as_fav_link3);    $as_location = addslashes($location);    $query = "UPDATE personalia              SET photo = '$ue_photo_url',                  homepage = '$ue_homepage_url',                  link1 = '$ue_fav_link1',                  link2 = '$ue_fav_link2',                  link3 = '$ue_fav_link3',                  location = '$as_location',                  country = '$country',                  gender = '$gender',                  priv_profile = $priv_profile              WHERE user_name = '$user_name'";    $result = mysql_query($query);    if (!$result) {      $status_message = 'Problem with user data entry';    } else {      $status_message = 'Successfully edited user data';    }  } elseif (strlen($_POST['gender']) > 1 && strlen($_POST['priv_profile']) > 1) {    // Bad user, smack on wrist    $status_message = 'You\'re trying to do something very odd with this form.  Stop it now.';  }  // Get previously-existing data  $query = "SELECT photo, homepage, link1, link2, link3, location, country, gender, priv_profile            FROM personalia            WHERE user_name = '$user_name'";  $result = mysql_query($query);  // Shall we have an error message if no data comes back?  $user_array = mysql_fetch_array($result);  $photo_url = urldecode($user_array['photo']);  $photo_url = stripslashes($photo_url);  $homepage_url = urldecode($user_array['homepage']);  $homepage_url = stripslashes($homepage_url);  $fav_link1 = urldecode($user_array['link1']);  $fav_link1 = stripslashes($fav_link1);  $fav_link2 = urldecode($user_array['link2']);  $fav_link2 = stripslashes($fav_link2);  $fav_link3 = urldecode($user_array['link3']);  $fav_link3 = stripslashes($fav_link3);  $location = stripslashes($user_array['location']);  $country = $user_array['country'];  $gender = $user_array['gender'];  // Construct the multiple field types  if ($gender == "M") {    $gender_button_str = '<INPUT TYPE="RADIO" NAME="gender" VALUE="M" CHECKED>M<INPUT TYPE="RADIO" NAME="gender" VALUE="F">F';  } elseif ($gender == "F") {    $gender_button_str = '<INPUT TYPE="RADIO" NAME="gender" VALUE="M">M<INPUT TYPE="RADIO" NAME="gender" VALUE="F" CHECKED>F';  } else {    $gender_button_str = '<INPUT TYPE="RADIO" NAME="gender" VALUE="M">M<INPUT TYPE="RADIO" NAME="gender" VALUE="F">F';  }  $priv_profile = $user_array['priv_profile'];  if ($priv_profile == 1) {    $priv_profile_str = '<INPUT TYPE="RADIO" NAME="priv_profile" VALUE="1" CHECKED>Yes<INPUT TYPE="RADIO" NAME="priv_profile" VALUE="0">No';  } elseif ($priv_profile == 0) {    $priv_profile_str = '<INPUT TYPE="RADIO" NAME="priv_profile" VALUE="1">Yes<INPUT TYPE="RADIO" NAME="priv_profile" VALUE="0" CHECKED>No';  } else {    $priv_profile_str = '<INPUT TYPE="RADIO" NAME="priv_profile" VALUE="1">Yes<INPUT TYPE="RADIO" NAME="priv_profile" VALUE="0">No';  }  // --------------  // Construct form  // --------------  site_header('User data edit page');  $userform_str = <<< EOUSERFORMSTR<TABLE ALIGN=CENTER WIDTH=621><TR>  <TD ROWSPAN=10><IMG WIDTH=15 HEIGHT=1 SRC="../images/spacer.gif"></TD>  <TD WIDTH=606></TD></TR><TR> <TD><P CLASS=bold>USER PROFILE<BR><BR><A HREF='/prefs_veranderemail.php'>verander jouw email </A><BR><BR><A HREF='/prefs_veranderpass.php'>Change your password</A><P><FONT COLOR="#ff0000">$status_message</FONT></P><FORM ACTION="$PHP_SELF" METHOD="POST"><P CLASS=left><B>Photo URL</B> (i.e. http://www.my.com/foto.jpg)<BR><INPUT TYPE="TEXT" NAME="photo_url" VALUE="$photo_url" SIZE="40"></P><P CLASS=left><B>Homepage URL </B>(e.g. http://www.my.com/page.html)<BR><INPUT TYPE="TEXT" NAME="homepage_url" VALUE="$homepage_url" SIZE="40"></P><P CLASS=bold>Favorite links<BR><INPUT TYPE="TEXT" NAME="fav_link1" VALUE="$fav_link1" SIZE="40"></P><P><INPUT TYPE="TEXT" NAME="fav_link2" VALUE="$fav_link2" SIZE="40"></P><P><INPUT TYPE="TEXT" NAME="fav_link3" VALUE="$fav_link3" SIZE="40"></P><P CLASS=left><B>Location</B> (City, State)<BR><INPUT TYPE="TEXT" NAME="location" VALUE="$location" SIZE="35" MAXLENGTH="50"></P><P CLASS=left><B>Country<BR><INPUT TYPE="TEXT" NAME="country" VALUE="$country" SIZE="35" MAXLENGTH="50"></P><P CLASS=bold>Gender<BR>$gender_button_str</P><P CLASS=bold>Make user profile private?<BR>$priv_profile_str</P><P><INPUT TYPE="SUBMIT" NAME="submit" VALUE="Edit user data"></FORM> </TD></TR></TABLE>EOUSERFORMSTR;  echo $userform_str;  site_footer();}?>